        rebal_freq = self.params.get('rebal_freq', 21)
        top_n = self.params.get('top_n', 3)
        sma_window = self.params.get('sma_window', 200)
        vol_window = self.params.get('vol_window', 21)
        max_position = self.params.get('max_position', 0.95)

        all_syms = list(data.keys())
        dates = data[all_syms[0]].index
        n = len(dates)

        sig = {s: np.zeros(n, dtype=int) for s in all_syms}
        sz = {s: np.zeros(n, dtype=float) for s in all_syms}

        min_bar = 252 + 10
        holdings = {}

        def vaa_score(px, i):
            periods = [21, 63, 126, 252]
            weights = [12, 4, 2, 1]
            score = 0.0
            for period, w in zip(periods, weights):
                if i < period:
                    return None
                p0 = float(px[i])
                pp = float(px[i - period])
                if pp <= 0:
                    return None
                score += w * (p0 / pp - 1.0)
            return score

        for i in range(min_bar, n):
            if i % rebal_freq != 0:
                for s, w in holdings.items():
                    sig[s][i] = 1
                    sz[s][i] = w
                continue

            scores = {}
            above_sma = {}
            for s in all_syms:
                px = data[s]['close'].values
                sc = vaa_score(px, i)
                if sc is None:
                    continue
                scores[s] = sc
                sma = float(np.mean(px[max(0, i - sma_window + 1):i + 1]))
                above_sma[s] = float(px[i]) > sma

            if not scores:
                holdings = {}
            else:
                ranked = sorted(scores.keys(), key=lambda s: scores[s], reverse=True)

                # Qualified: positive score AND above 200-day SMA
                qualified = [s for s in ranked if scores[s] > 0 and above_sma.get(s, False)]
                candidates = qualified[:top_n]

                if not candidates:
                    # No qualified equity — fall back to best defensive by score
                    defensive = [s for s in ['AGG', 'TLT', 'GLD'] if s in scores]
                    if defensive:
                        best_def = max(defensive, key=lambda s: scores[s])
                        candidates = [best_def]
                    elif ranked:
                        candidates = [ranked[0]]

                if candidates:
