                    vols = {}
                    for s in candidates:
                        px = data[s]['close'].values
                        rets = np.diff(np.log(px[max(0, i - vol_window):i + 1]))
                        vols[s] = float(np.std(rets) * np.sqrt(252)) if len(rets) > 1 else 0.15

                    inv_vols = {s: 1.0 / max(v, 0.01) for s, v in vols.items()}
                    total_inv = sum(inv_vols.values())
                    holdings = {s: float((iv / total_inv) * max_position)
                                for s, iv in inv_vols.items()}
                else:
                    holdings = {}

            for s in all_syms:
                sig[s][i] = 0
                sz[s][i] = 0.0
            for s, w in holdings.items():
                if s in data:
                    sig[s][i] = 1
                    sz[s][i] = float(w)

        return {s: pd.DataFrame({'signal': sig[s], 'size_pct': sz[s]}, index=dates)
                for s in all_syms}
